// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Liveness probe.
	// (GET /health)
	GetHealth(w http.ResponseWriter, r *http.Request)
	// Resolve an account number to a masked owner label.
	// (GET /v1/accounts/resolve/{accountNumber})
	GetV1AccountsResolveAccountNumber(w http.ResponseWriter, r *http.Request, accountNumber string)
	// Issue an Ed25519-signed device session token. The token authorizes
	// offline-scope operations on this device (PIN/biometric-gated) when the
	// app starts cold without internet. Token verification is purely local
	// against the embedded `server_public_key`.
	// (POST /v1/auth/device-session)
	PostV1AuthDeviceSession(w http.ResponseWriter, r *http.Request)
	// Return the active server public key(s) the device should trust when
	// verifying device session tokens offline. Cached at registration; the
	// device falls back to the cache if this endpoint is unreachable.
	// (GET /v1/auth/device-session/public-keys)
	GetV1AuthDeviceSessionPublicKeys(w http.ResponseWriter, r *http.Request)
	// Confirm the email-verification OTP for the authenticated user.
	// (POST /v1/auth/email/verify/confirm)
	PostV1AuthEmailVerifyConfirm(w http.ResponseWriter, r *http.Request)
	// Dispatch an email-verification OTP for the authenticated user.
	// (POST /v1/auth/email/verify/request)
	PostV1AuthEmailVerifyRequest(w http.ResponseWriter, r *http.Request)
	// Dispatch a password-reset OTP by email. Always returns 204 (no enumeration).
	// (POST /v1/auth/forgot-password/request)
	PostV1AuthForgotPasswordRequest(w http.ResponseWriter, r *http.Request)
	// Reset a password by email + OTP.
	// (POST /v1/auth/forgot-password/reset)
	PostV1AuthForgotPasswordReset(w http.ResponseWriter, r *http.Request)
	// Authenticate with phone + password.
	// (POST /v1/auth/login)
	PostV1AuthLogin(w http.ResponseWriter, r *http.Request)
	// Revoke a refresh token.
	// (POST /v1/auth/logout)
	PostV1AuthLogout(w http.ResponseWriter, r *http.Request)
	// Set (or replace) the authenticated user's transaction PIN.
	// (POST /v1/auth/pin)
	PostV1AuthPin(w http.ResponseWriter, r *http.Request)
	// Rotate a refresh token.
	// (POST /v1/auth/refresh)
	PostV1AuthRefresh(w http.ResponseWriter, r *http.Request)
	// List the authenticated user's active refresh sessions.
	// (GET /v1/auth/sessions)
	GetV1AuthSessions(w http.ResponseWriter, r *http.Request)
	// Revoke every session for the caller except the current one.
	// (POST /v1/auth/sessions/revoke-all-others)
	PostV1AuthSessionsRevokeAllOthers(w http.ResponseWriter, r *http.Request)
	// Revoke a single session owned by the authenticated user.
	// (POST /v1/auth/sessions/{id}/revoke)
	PostV1AuthSessionsIdRevoke(w http.ResponseWriter, r *http.Request, id string)
	// Register a new user (phone + password + profile). Lands at KYC tier TIER_1.
	// (POST /v1/auth/signup)
	PostV1AuthSignup(w http.ResponseWriter, r *http.Request)
	// Register a new device for the authenticated user.
	// (POST /v1/devices)
	PostV1Devices(w http.ResponseWriter, r *http.Request)
	// Obtain a fresh server-issued attestation nonce.
	// (POST /v1/devices/attestation-challenge)
	PostV1DevicesAttestationChallenge(w http.ResponseWriter, r *http.Request)
	// Remove an FCM push token for the authenticated user.
	// (DELETE /v1/devices/push-token)
	DeleteV1DevicesPushToken(w http.ResponseWriter, r *http.Request)
	// Register (or refresh) an FCM push token for the authenticated user.
	// (POST /v1/devices/push-token)
	PostV1DevicesPushToken(w http.ResponseWriter, r *http.Request)
	// Provision a replacement device via recovery proof (keyless).
	// (POST /v1/devices/recover)
	PostV1DevicesRecover(w http.ResponseWriter, r *http.Request)
	// Rotate to a new device (retires the old one atomically).
	// (POST /v1/devices/rotate)
	PostV1DevicesRotate(w http.ResponseWriter, r *http.Request)
	// Re-attest an existing device and receive a fresh device JWT.
	// (POST /v1/devices/{deviceId}/attest)
	PostV1DevicesDeviceIdAttest(w http.ResponseWriter, r *http.Request, deviceId string)
	// Deactivate a device owned by the authenticated user.
	// (POST /v1/devices/{deviceId}/deactivate)
	PostV1DevicesDeviceIdDeactivate(w http.ResponseWriter, r *http.Request, deviceId string)
	// Revoke another device belonging to the authenticated user.
	// (POST /v1/devices/{deviceId}/revoke)
	PostV1DevicesDeviceIdRevoke(w http.ResponseWriter, r *http.Request, deviceId string)
	// Fetch the caller's currently-issued DisplayCard.
	// (GET /v1/identity/display-card)
	GetV1IdentityDisplayCard(w http.ResponseWriter, r *http.Request)
	// Fetch bank Ed25519 public keys (keyless).
	// (POST /v1/keys/bank-public-keys)
	PostV1KeysBankPublicKeys(w http.ResponseWriter, r *http.Request)
	// Fetch all active realm key versions in the overlap window.
	// (GET /v1/keys/realm/active)
	GetV1KeysRealmActive(w http.ResponseWriter, r *http.Request, params GetV1KeysRealmActiveParams)
	// Fetch a specific realm key version (authed, device-scoped).
	// (GET /v1/keys/realm/{version})
	GetV1KeysRealmVersion(w http.ResponseWriter, r *http.Request, version int32, params GetV1KeysRealmVersionParams)
	// Fetch the server's X25519 sealed-box public key (keyless).
	// (GET /v1/keys/sealed-box-pubkey)
	GetV1KeysSealedBoxPubkey(w http.ResponseWriter, r *http.Request)
	// Dev helper — expected mock NIN/BVN for the caller's phone.
	// (GET /v1/kyc/hint)
	GetV1KycHint(w http.ResponseWriter, r *http.Request)
	// List the caller's KYC submission history.
	// (GET /v1/kyc/submissions)
	GetV1KycSubmissions(w http.ResponseWriter, r *http.Request)
	// Submit a NIN (promotes to TIER_2) or BVN (promotes to TIER_3).
	// (POST /v1/kyc/submit)
	PostV1KycSubmit(w http.ResponseWriter, r *http.Request)
	// Fetch the authenticated user's profile.
	// (GET /v1/me)
	GetV1Me(w http.ResponseWriter, r *http.Request)
	// Submit a batch of offline payment tokens for claim (Phase 4a).
	// (POST /v1/settlement/claims)
	PostV1SettlementClaims(w http.ResponseWriter, r *http.Request)
	// Fetch a previously submitted batch receipt.
	// (GET /v1/settlement/claims/{batchId})
	GetV1SettlementClaimsBatchID(w http.ResponseWriter, r *http.Request, batchId string)
	// Upload carried gossip blobs for settlement decryption and routing.
	// (POST /v1/settlement/gossip)
	PostV1SettlementGossip(w http.ResponseWriter, r *http.Request)
	// Sync payer-side and receiver-side settled transactions for reconciliation.
	// (POST /v1/settlement/sync)
	PostV1SettlementSync(w http.ResponseWriter, r *http.Request)
	// List transfers for the authenticated user (sender or receiver).
	// (GET /v1/transfers)
	GetV1Transfers(w http.ResponseWriter, r *http.Request, params GetV1TransfersParams)
	// Initiate a user-to-user transfer.
	// (POST /v1/transfers)
	PostV1Transfers(w http.ResponseWriter, r *http.Request)
	// Fetch a transfer by id (must be a party).
	// (GET /v1/transfers/{id})
	GetV1TransfersID(w http.ResponseWriter, r *http.Request, id string)
	// Fetch all five account balances for the authenticated user.
	// (GET /v1/wallet/balances)
	GetV1WalletBalances(w http.ResponseWriter, r *http.Request)
	// Fetch the payer's current non-terminal ceiling (ACTIVE or
	// RECOVERY_PENDING) with live settled / remaining totals. Used by
	// the mobile client to render the tri-state offline-wallet card
	// and to converge local state after a recovery.
	// (GET /v1/wallet/ceiling/current)
	GetV1WalletCeilingCurrent(w http.ResponseWriter, r *http.Request)
	// Debit main wallet, place lien, and issue a fresh ceiling token.
	// (POST /v1/wallet/fund-offline)
	PostV1WalletFundOffline(w http.ResponseWriter, r *http.Request)
	// Revoke active ceiling and release lien back to the main wallet.
	// (POST /v1/wallet/move-to-main)
	PostV1WalletMoveToMain(w http.ResponseWriter, r *http.Request)
	// Begin recovery of a ceiling whose device-side token was lost. The
	// lien stays locked during a quarantine window (expires_at +
	// auto_settle_timeout + grace) so any offline-carried claims can
	// still land; the expiry sweep then returns the remaining lien to
	// the main wallet.
	// (POST /v1/wallet/recover-offline-ceiling)
	PostV1WalletRecoverOfflineCeiling(w http.ResponseWriter, r *http.Request)
	// Consume the remaining ceiling into a fresh one with a new amount/TTL.
	// (POST /v1/wallet/refresh-ceiling)
	PostV1WalletRefreshCeiling(w http.ResponseWriter, r *http.Request)
	// Dev-only endpoint to credit the user's main wallet with fake funds.
	// (POST /v1/wallet/top-up)
	PostV1WalletTopUp(w http.ResponseWriter, r *http.Request)
}

