// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Liveness probe.
	// (GET /health)
	GetHealth(ctx context.Context, request GetHealthRequestObject) (GetHealthResponseObject, error)
	// Resolve an account number to a masked owner label.
	// (GET /v1/accounts/resolve/{accountNumber})
	GetV1AccountsResolveAccountNumber(ctx context.Context, request GetV1AccountsResolveAccountNumberRequestObject) (GetV1AccountsResolveAccountNumberResponseObject, error)
	// Issue an Ed25519-signed device session token. The token authorizes
	// offline-scope operations on this device (PIN/biometric-gated) when the
	// app starts cold without internet. Token verification is purely local
	// against the embedded `server_public_key`.
	// (POST /v1/auth/device-session)
	PostV1AuthDeviceSession(ctx context.Context, request PostV1AuthDeviceSessionRequestObject) (PostV1AuthDeviceSessionResponseObject, error)
	// Return the active server public key(s) the device should trust when
	// verifying device session tokens offline. Cached at registration; the
	// device falls back to the cache if this endpoint is unreachable.
	// (GET /v1/auth/device-session/public-keys)
	GetV1AuthDeviceSessionPublicKeys(ctx context.Context, request GetV1AuthDeviceSessionPublicKeysRequestObject) (GetV1AuthDeviceSessionPublicKeysResponseObject, error)
	// Confirm the email-verification OTP for the authenticated user.
	// (POST /v1/auth/email/verify/confirm)
	PostV1AuthEmailVerifyConfirm(ctx context.Context, request PostV1AuthEmailVerifyConfirmRequestObject) (PostV1AuthEmailVerifyConfirmResponseObject, error)
	// Dispatch an email-verification OTP for the authenticated user.
	// (POST /v1/auth/email/verify/request)
	PostV1AuthEmailVerifyRequest(ctx context.Context, request PostV1AuthEmailVerifyRequestRequestObject) (PostV1AuthEmailVerifyRequestResponseObject, error)
	// Dispatch a password-reset OTP by email. Always returns 204 (no enumeration).
	// (POST /v1/auth/forgot-password/request)
	PostV1AuthForgotPasswordRequest(ctx context.Context, request PostV1AuthForgotPasswordRequestRequestObject) (PostV1AuthForgotPasswordRequestResponseObject, error)
	// Reset a password by email + OTP.
	// (POST /v1/auth/forgot-password/reset)
	PostV1AuthForgotPasswordReset(ctx context.Context, request PostV1AuthForgotPasswordResetRequestObject) (PostV1AuthForgotPasswordResetResponseObject, error)
	// Authenticate with phone + password.
	// (POST /v1/auth/login)
	PostV1AuthLogin(ctx context.Context, request PostV1AuthLoginRequestObject) (PostV1AuthLoginResponseObject, error)
	// Revoke a refresh token.
	// (POST /v1/auth/logout)
	PostV1AuthLogout(ctx context.Context, request PostV1AuthLogoutRequestObject) (PostV1AuthLogoutResponseObject, error)
	// Set (or replace) the authenticated user's transaction PIN.
	// (POST /v1/auth/pin)
	PostV1AuthPin(ctx context.Context, request PostV1AuthPinRequestObject) (PostV1AuthPinResponseObject, error)
	// Rotate a refresh token.
	// (POST /v1/auth/refresh)
	PostV1AuthRefresh(ctx context.Context, request PostV1AuthRefreshRequestObject) (PostV1AuthRefreshResponseObject, error)
	// List the authenticated user's active refresh sessions.
	// (GET /v1/auth/sessions)
	GetV1AuthSessions(ctx context.Context, request GetV1AuthSessionsRequestObject) (GetV1AuthSessionsResponseObject, error)
	// Revoke every session for the caller except the current one.
	// (POST /v1/auth/sessions/revoke-all-others)
	PostV1AuthSessionsRevokeAllOthers(ctx context.Context, request PostV1AuthSessionsRevokeAllOthersRequestObject) (PostV1AuthSessionsRevokeAllOthersResponseObject, error)
	// Revoke a single session owned by the authenticated user.
	// (POST /v1/auth/sessions/{id}/revoke)
	PostV1AuthSessionsIdRevoke(ctx context.Context, request PostV1AuthSessionsIdRevokeRequestObject) (PostV1AuthSessionsIdRevokeResponseObject, error)
	// Register a new user (phone + password + profile). Lands at KYC tier TIER_1.
	// (POST /v1/auth/signup)
	PostV1AuthSignup(ctx context.Context, request PostV1AuthSignupRequestObject) (PostV1AuthSignupResponseObject, error)
	// Register a new device for the authenticated user.
	// (POST /v1/devices)
	PostV1Devices(ctx context.Context, request PostV1DevicesRequestObject) (PostV1DevicesResponseObject, error)
	// Obtain a fresh server-issued attestation nonce.
	// (POST /v1/devices/attestation-challenge)
	PostV1DevicesAttestationChallenge(ctx context.Context, request PostV1DevicesAttestationChallengeRequestObject) (PostV1DevicesAttestationChallengeResponseObject, error)
	// Remove an FCM push token for the authenticated user.
	// (DELETE /v1/devices/push-token)
	DeleteV1DevicesPushToken(ctx context.Context, request DeleteV1DevicesPushTokenRequestObject) (DeleteV1DevicesPushTokenResponseObject, error)
	// Register (or refresh) an FCM push token for the authenticated user.
	// (POST /v1/devices/push-token)
	PostV1DevicesPushToken(ctx context.Context, request PostV1DevicesPushTokenRequestObject) (PostV1DevicesPushTokenResponseObject, error)
	// Provision a replacement device via recovery proof (keyless).
	// (POST /v1/devices/recover)
	PostV1DevicesRecover(ctx context.Context, request PostV1DevicesRecoverRequestObject) (PostV1DevicesRecoverResponseObject, error)
	// Rotate to a new device (retires the old one atomically).
	// (POST /v1/devices/rotate)
	PostV1DevicesRotate(ctx context.Context, request PostV1DevicesRotateRequestObject) (PostV1DevicesRotateResponseObject, error)
	// Re-attest an existing device and receive a fresh device JWT.
	// (POST /v1/devices/{deviceId}/attest)
	PostV1DevicesDeviceIdAttest(ctx context.Context, request PostV1DevicesDeviceIdAttestRequestObject) (PostV1DevicesDeviceIdAttestResponseObject, error)
	// Deactivate a device owned by the authenticated user.
	// (POST /v1/devices/{deviceId}/deactivate)
	PostV1DevicesDeviceIdDeactivate(ctx context.Context, request PostV1DevicesDeviceIdDeactivateRequestObject) (PostV1DevicesDeviceIdDeactivateResponseObject, error)
	// Revoke another device belonging to the authenticated user.
	// (POST /v1/devices/{deviceId}/revoke)
	PostV1DevicesDeviceIdRevoke(ctx context.Context, request PostV1DevicesDeviceIdRevokeRequestObject) (PostV1DevicesDeviceIdRevokeResponseObject, error)
	// Fetch the caller's currently-issued DisplayCard.
	// (GET /v1/identity/display-card)
	GetV1IdentityDisplayCard(ctx context.Context, request GetV1IdentityDisplayCardRequestObject) (GetV1IdentityDisplayCardResponseObject, error)
	// Fetch bank Ed25519 public keys (keyless).
	// (POST /v1/keys/bank-public-keys)
	PostV1KeysBankPublicKeys(ctx context.Context, request PostV1KeysBankPublicKeysRequestObject) (PostV1KeysBankPublicKeysResponseObject, error)
	// Fetch all active realm key versions in the overlap window.
	// (GET /v1/keys/realm/active)
	GetV1KeysRealmActive(ctx context.Context, request GetV1KeysRealmActiveRequestObject) (GetV1KeysRealmActiveResponseObject, error)
	// Fetch a specific realm key version (authed, device-scoped).
	// (GET /v1/keys/realm/{version})
	GetV1KeysRealmVersion(ctx context.Context, request GetV1KeysRealmVersionRequestObject) (GetV1KeysRealmVersionResponseObject, error)
	// Fetch the server's X25519 sealed-box public key (keyless).
	// (GET /v1/keys/sealed-box-pubkey)
	GetV1KeysSealedBoxPubkey(ctx context.Context, request GetV1KeysSealedBoxPubkeyRequestObject) (GetV1KeysSealedBoxPubkeyResponseObject, error)
	// Dev helper — expected mock NIN/BVN for the caller's phone.
	// (GET /v1/kyc/hint)
	GetV1KycHint(ctx context.Context, request GetV1KycHintRequestObject) (GetV1KycHintResponseObject, error)
	// List the caller's KYC submission history.
	// (GET /v1/kyc/submissions)
	GetV1KycSubmissions(ctx context.Context, request GetV1KycSubmissionsRequestObject) (GetV1KycSubmissionsResponseObject, error)
	// Submit a NIN (promotes to TIER_2) or BVN (promotes to TIER_3).
	// (POST /v1/kyc/submit)
	PostV1KycSubmit(ctx context.Context, request PostV1KycSubmitRequestObject) (PostV1KycSubmitResponseObject, error)
	// Fetch the authenticated user's profile.
	// (GET /v1/me)
	GetV1Me(ctx context.Context, request GetV1MeRequestObject) (GetV1MeResponseObject, error)
	// Submit a batch of offline payment tokens for claim (Phase 4a).
	// (POST /v1/settlement/claims)
	PostV1SettlementClaims(ctx context.Context, request PostV1SettlementClaimsRequestObject) (PostV1SettlementClaimsResponseObject, error)
	// Fetch a previously submitted batch receipt.
	// (GET /v1/settlement/claims/{batchId})
	GetV1SettlementClaimsBatchID(ctx context.Context, request GetV1SettlementClaimsBatchIDRequestObject) (GetV1SettlementClaimsBatchIDResponseObject, error)
	// Upload carried gossip blobs for settlement decryption and routing.
	// (POST /v1/settlement/gossip)
	PostV1SettlementGossip(ctx context.Context, request PostV1SettlementGossipRequestObject) (PostV1SettlementGossipResponseObject, error)
	// Sync payer-side and receiver-side settled transactions for reconciliation.
	// (POST /v1/settlement/sync)
	PostV1SettlementSync(ctx context.Context, request PostV1SettlementSyncRequestObject) (PostV1SettlementSyncResponseObject, error)
	// List transfers for the authenticated user (sender or receiver).
	// (GET /v1/transfers)
	GetV1Transfers(ctx context.Context, request GetV1TransfersRequestObject) (GetV1TransfersResponseObject, error)
	// Initiate a user-to-user transfer.
	// (POST /v1/transfers)
	PostV1Transfers(ctx context.Context, request PostV1TransfersRequestObject) (PostV1TransfersResponseObject, error)
	// Fetch a transfer by id (must be a party).
	// (GET /v1/transfers/{id})
	GetV1TransfersID(ctx context.Context, request GetV1TransfersIDRequestObject) (GetV1TransfersIDResponseObject, error)
	// Fetch all five account balances for the authenticated user.
	// (GET /v1/wallet/balances)
	GetV1WalletBalances(ctx context.Context, request GetV1WalletBalancesRequestObject) (GetV1WalletBalancesResponseObject, error)
	// Fetch the payer's current non-terminal ceiling (ACTIVE or
	// RECOVERY_PENDING) with live settled / remaining totals. Used by
	// the mobile client to render the tri-state offline-wallet card
	// and to converge local state after a recovery.
	// (GET /v1/wallet/ceiling/current)
	GetV1WalletCeilingCurrent(ctx context.Context, request GetV1WalletCeilingCurrentRequestObject) (GetV1WalletCeilingCurrentResponseObject, error)
	// Debit main wallet, place lien, and issue a fresh ceiling token.
	// (POST /v1/wallet/fund-offline)
	PostV1WalletFundOffline(ctx context.Context, request PostV1WalletFundOfflineRequestObject) (PostV1WalletFundOfflineResponseObject, error)
	// Revoke active ceiling and release lien back to the main wallet.
	// (POST /v1/wallet/move-to-main)
	PostV1WalletMoveToMain(ctx context.Context, request PostV1WalletMoveToMainRequestObject) (PostV1WalletMoveToMainResponseObject, error)
	// Begin recovery of a ceiling whose device-side token was lost. The
	// lien stays locked during a quarantine window (expires_at +
	// auto_settle_timeout + grace) so any offline-carried claims can
	// still land; the expiry sweep then returns the remaining lien to
	// the main wallet.
	// (POST /v1/wallet/recover-offline-ceiling)
	PostV1WalletRecoverOfflineCeiling(ctx context.Context, request PostV1WalletRecoverOfflineCeilingRequestObject) (PostV1WalletRecoverOfflineCeilingResponseObject, error)
	// Consume the remaining ceiling into a fresh one with a new amount/TTL.
	// (POST /v1/wallet/refresh-ceiling)
	PostV1WalletRefreshCeiling(ctx context.Context, request PostV1WalletRefreshCeilingRequestObject) (PostV1WalletRefreshCeilingResponseObject, error)
	// Dev-only endpoint to credit the user's main wallet with fake funds.
	// (POST /v1/wallet/top-up)
	PostV1WalletTopUp(ctx context.Context, request PostV1WalletTopUpRequestObject) (PostV1WalletTopUpResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// GetHealth operation middleware
func (sh *strictHandler) GetHealth(w http.ResponseWriter, r *http.Request) {
	var request GetHealthRequestObject

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.GetHealth(ctx, request.(GetHealthRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "GetHealth")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(GetHealthResponseObject); ok {
		if err := validResponse.VisitGetHealthResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

// GetV1AccountsResolveAccountNumber operation middleware
